class SayiTahminOyunu {
    constructor() {
        this.hedef = Math.floor(Math.random() * 100) + 1;
        this.deneme = 0;
    }
    tahmin(sayi) {
        this.deneme++;
        if (sayi === this.hedef) return 'Bildin! ' + this.deneme + '. deneme';
        return sayi < this.hedef ? 'Yuksek!' : 'Dusuk!';
    }
}
